# Define a simple Product class for testing
class Product:
    def __init__(self, product_id, name, price, stock):
        self.product_id = product_id
        self.name = name
        self.price = price
        self.stock = stock

    def __repr__(self):
        return f"Product(id={self.product_id}, name='{self.name}', price={self.price}, stock={self.stock})"


class ShoppingCart:
    def __init__(self, coupon_repository):
        self.items = {}  # {product_id: quantity}
        self.coupons = coupon_repository

    def add_item(self, product, quantity=1):
        if product.product_id not in self.items:
            self.items[product.product_id] = 0
        self.items[product.product_id] += quantity

    def remove_item(self, product_id):
        if product_id in self.items:
            del self.items[product_id]

    def update_quantity(self, product_id, quantity):
        if product_id in self.items:
            if quantity < 0:
                raise ValueError("Quantity cannot be negative.")
            self.items[product_id] = quantity
        else:
            raise ValueError("Product not in cart.")

    def apply_coupon(self, coupon_code):
        coupon = self.coupons.get_coupon(coupon_code)
        if not coupon:
            raise ValueError("Invalid coupon code.")
        if datetime.now() > coupon.expiration_date:
            raise ValueError("Coupon has expired.")
        self.coupon = coupon
        return True

    def calculate_total(self):
        total = 0
        for product_id, quantity in self.items.items():
            product = self.coupons.get_product(product_id)  # Assume coupon repo knows products
            if not product:
                raise ValueError(f"Product with ID {product_id} not found.")
            if product.stock < quantity:
                raise ValueError(f"Not enough stock for product {product.name}.")
            total += product.price * quantity

        if hasattr(self, 'coupon'):
            total *= (1 - self.coupon.discount)
        return total


