const express = require('express');
const app = express();
const path = require('path');
const crypto = require('crypto');
const fileType = require('file-type'); // npm install file-type

const uploadsDir = path.join(__dirname, 'uploads');

// Ensure the uploads directory exists
if (!require('fs').existsSync(uploadsDir)) {
  require('fs').mkdirSync(uploadsDir);
}

app.post('/upload', async (req, res) => {
  try {
    if (!req.body.filename || !req.body.data) {
      return res.status(400).json({ status: 'error', message: 'Missing filename or data' });
    }

    const filename = req.body.filename;
    const fileData = req.body.data;

    // Input Validation
    const allowedFilenameRegex = /^[a-zA-Z0-9._-]+$/; // Example: alphanumeric, period, underscore, hyphen
    if (!allowedFilenameRegex.test(filename)) {
      return res.status(400).json({ status: 'error', message: 'Invalid filename' });
    }

    // File Type Validation (Example: allow only images)
    const fileBuffer = Buffer.from(fileData, 'base64'); // Assuming data is base64 encoded
    const fileInfo = await fileType.fromBuffer(fileBuffer);
    if (!fileInfo || !fileInfo.mime.startsWith('image/')) {
      return res.status(400).json({ status: 'error', message: 'Only images are allowed' });
    }

    // Generate a unique filename
    const uniqueFilename = crypto.randomBytes(16).toString('hex') + path.extname(filename);
    const filePath = path.join(uploadsDir, uniqueFilename);

    // Write the file
    require('fs').writeFileSync(filePath, fileBuffer);

    res.json({ status: 'ok', filename: uniqueFilename });

  } catch (error) {
    console.error('Upload error:', error);
    res.status(500).json({ status: 'error', message: 'Upload failed' });
  }
